message:
Command `MCU_DIR="/workspace/nc-project-20260529-210526/mspm33c321a_derivative_mcu"
WRAPPER_RUN="$MCU_DIR/openlane/mspm33c321a_derivative_mcu_wrapper/runs/wrapper_run"
DRT_ODB="$WRAPPER_RUN/67-openroad-repairantennas/1-openroad-diodeinsertion/mspm33c321a_derivative_mcu_wrapper.odb"
FIXED_ODB="$WRAPPER_RUN/67-openroad-repairantennas/1-openroad-diodeinsertion/mspm33c321a_derivative_mcu_wrapper_fixed.odb"

# Write the Tcl script cleanly (avoid shell substitution issues)
python3 -c "
script = '''
read_db {drt_odb}
set block [ord::get_db_block]

foreach net_name {{VDDIO VSSIO}} {{
    set net [\\$block findNet \\$net_name]
    if {{ \\$net == \"NULL\" }} {{
        puts \"Net \\$net_name: not found, skipping\"
        continue
    }}
    set bterms [\\$net getBTerms]
    puts \"Net \\$net_name: [llength \\$bterms] bterms\"
    foreach bterm \\$bterms {{
        set bpins [\\$bterm getBPins]
        puts \"  bterm [\\$bterm getName]: [llength \\$bpins] bpins\"
        set first 1
        foreach bpin \\$bpins {{
            if {{ \\$first }} {{
                set first 0
                continue
            }}
            odb::dbBPin_destroy \\$bpin
        }}
        set bpins_after [\\$bterm getBPins]
        puts \"  after: [llength \\$bpins_after] bpins\"
    }}
}}

write_db {fixed_odb}
puts \"Done: {fixed_odb}\"
'''.format(drt_odb='$DRT_ODB', fixed_odb='$FIXED_ODB')
with open('/tmp/fix_vddio2.tcl', 'w') as f:
    f.write(script)
print('Script written')
"

echo ""
echo "=== Running fix ==="
openroad -no_init -exit /tmp/fix_vddio2.tcl 2>&1 | grep -v "^OpenROAD\|^Copyright\|^This\|^Component\|^Features\|^License\|^Reading" | grep -v "^$" | head -20` executed with exit code 0.

